// Import dependencies
const cron = require('node-cron');
const mongoose = require('mongoose');
const Task = require('./models/Task');
const NotificationService = require('./services/NotificationService');
require('dotenv').config();

/**
 * Schedule the task notifications based on their recurrence settings.
 * This function sets up cron jobs for each task that needs notifications.
 */
const scheduleTasks = async () => {
  try {
    // Fetch all active tasks with recurrence
    const tasks = await Task.find({ status: 'active' });

    tasks.forEach(task => {
      const { rotationIndex, recurrence } = task;
      const nextNotificationTime = calculateNextNotificationTime(recurrence);

      // Setup cron job
      cron.schedule(nextNotificationTime, async () => {
        const currentAssignee = task.assignees[rotationIndex];

        // Check if the current assignee is available
        if (!task.unavailableMembers.includes(currentAssignee)) {
          // Send notification
          await NotificationService.sendNotification(task, currentAssignee);

          // Increment rotation index
          task.rotationIndex = (rotationIndex + 1) % task.assignees.length;
          await task.save();
        }
      }, {
        scheduled: true,
        timezone: 'Asia/Bangkok' // Ensure handling of UTC+7
      });
    });
  } catch (error) {
    console.error('Failed to schedule tasks:', error);
  }
};

/**
 * Calculate the next notification time based on the recurrence configuration.
 * @param {Object} recurrence - The recurrence config of the task.
 * @returns {string} Cron time string.
 */
const calculateNextNotificationTime = (recurrence) => {
  const { type, time, daysOfWeek } = recurrence;

  // Define base cron structure
  let cronTime = '';
  switch (type) {
    case 'daily':
      cronTime = `0 ${time.split(':')[1]} ${time.split(':')[0]} * *`;
      break;
    case 'weekly':
      cronTime = `0 ${time.split(':')[1]} ${time.split(':')[0]} * ${daysOfWeek.join(',')}`;
      break;
    // Add more cases for custom recurrences as needed
    default:
      throw new Error('Unsupported recurrence type');
  }
  return cronTime;
};

// Connect to MongoDB and start the scheduling
mongoose.connect(process.env.MONGO_URI, { useNewUrlParser: true, useUnifiedTopology: true })
  .then(() => {
    console.log('Connected to MongoDB');
    scheduleTasks();
  })
  .catch(err => {
    console.error('MongoDB connection error:', err);
  });
